package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testTrim() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.newFormat(',').withQuote('"').withRecordSeparator("\r\n");
        CSVFormat csvFormatSpy = mock(CSVFormat.class);
        Method trimMethod = CSVFormat.class.getDeclaredMethod("trim", CharSequence.class);
        trimMethod.setAccessible(true);
        when(trimMethod.invoke(csvFormatSpy, "  test  ")).thenCallRealMethod();

        // When
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormatSpy, "  test  ");

        // Then
        assertEquals("test", result.toString());
    }
}
